import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import UserMenu from "./UserMenu"; // 1. Imported your brand new user dropdown menu

const Topbar = () => {
  const location = useLocation();
  // 2. State to track if the profile menu popover is visible or hidden
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleUserMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <div className="topbar-container">
      {/* Left side: Market Indices Layout */}
      <div className="indices-container">
        <p>
          NIFTY 50 <span className="index-val">100.2</span>
        </p>
        <p>
          SENSEX <span className="index-val">100.2</span>
        </p>
      </div>

      {/* Right side: Navigation Area Layout */}
      <div className="menu-container">
        <div className="menus">
          {/* Main Logo Container */}
          <img
            src="https://kite.zerodha.com/static/images/kite-logo.svg"
            alt="Kite Logo"
            className="logo"
          />

          <ul>
            <li>
              <Link
                to="/"
                className={`menu ${location.pathname === "/" ? "selected" : ""}`}
              >
                Dashboard
              </Link>
            </li>
            <li>
              <Link
                to="/orders"
                className={`menu ${location.pathname === "/orders" ? "selected" : ""}`}
              >
                Orders
              </Link>
            </li>
            <li>
              <Link
                to="/holdings"
                className={`menu ${location.pathname === "/holdings" ? "selected" : ""}`}
              >
                Holdings
              </Link>
            </li>
            <li>
              <Link
                to="/positions"
                className={`menu ${location.pathname === "/positions" ? "selected" : ""}`}
              >
                Positions
              </Link>
            </li>
            <li>
              <Link
                to="/funds"
                className={`menu ${location.pathname === "/funds" ? "selected" : ""}`}
              >
                Funds
              </Link>
            </li>
            <li>
              <Link
                to="/apps"
                className={`menu ${location.pathname === "/apps" ? "selected" : ""}`}
              >
                Apps
              </Link>
            </li>
          </ul>

          {/* Profile User Badge Wrapper - 3. Added relative positioning inline to align the dropdown perfectly */}
          <div
            className="avatar-container"
            onClick={toggleUserMenu}
            style={{ position: "relative", cursor: "pointer" }}
          >
            <span className="avatar">ZU</span>
            <span className="user-id">USERID</span>

            {/* 4. Conditional Renderer: Shows menu popup only when state equals true */}
            {isMenuOpen && <UserMenu />}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Topbar;
